9	type Item = { type: string };
10	type Step = { op: string; items: Item[] };
11	type Input = { steps: Step[] };
12	
13	const itemPremium = (item: Item): number => {
14	  const base = BASE_PREMIUMS[item.type] ?? 0;
15	  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
16	};
17	
18	const quotePremium = (step: Step): number => {
19	  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
20	  return Math.ceil(itemsTotal) + PROCESSING_FEE;
21	};
22	
23	export const runScenario = (input: unknown): unknown => {
24	  const { steps } = input as Input;
25	  const results = steps.map((step) => ({ premium: quotePremium(step) }));
26	  return { results };
27	};
